import{_ as a,o as i,c as t,a2 as r}from"./chunks/framework.C58al07P.js";const m=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/dashboard.md","filePath":"en/guide/dashboard.md"}'),o={name:"en/guide/dashboard.md"};function s(l,e,h,n,d,c){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>The Dashboard is the home page of Nid. It provides an overview of your Gmail mailbox with interactive charts.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Dashboard displays four statistics blocks, calculated in real time from the Gmail API:</p><blockquote><p>📸 <em>Suggested screenshot: full Dashboard page with the 4 blocks</em></p></blockquote><hr><h2 id="top-senders" tabindex="-1">Top senders <a class="header-anchor" href="#top-senders" aria-label="Permalink to &quot;Top senders&quot;">​</a></h2><p>A ranking of senders who send you the most emails, with two views:</p><ul><li><strong>By number of emails</strong>: who floods your mailbox</li><li><strong>By total size</strong>: who uses the most space</li></ul><p>This ranking is useful for quickly identifying senders to clean up or block.</p><blockquote><p>📸 <em>Suggested screenshot: Top senders chart (horizontal bars)</em></p></blockquote><hr><h2 id="largest-emails" tabindex="-1">Largest emails <a class="header-anchor" href="#largest-emails" aria-label="Permalink to &quot;Largest emails&quot;">​</a></h2><p>List of the largest emails in your mailbox, sorted by decreasing size. Click on an email to open it and decide whether you want to delete or archive it.</p><p>Ideal for quickly freeing up space in your Gmail quota.</p><hr><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2><p>Line chart showing the evolution of emails received per month. Helps identify activity spikes and trends.</p><blockquote><p>📸 <em>Suggested screenshot: Timeline chart (monthly curve)</em></p></blockquote><hr><h2 id="label-distribution" tabindex="-1">Label distribution <a class="header-anchor" href="#label-distribution" aria-label="Permalink to &quot;Label distribution&quot;">​</a></h2><p>Pie chart (or donut) showing the distribution of your Gmail labels. Useful for understanding how your emails are organized.</p><hr><h2 id="archive-statistics" tabindex="-1">Archive statistics <a class="header-anchor" href="#archive-statistics" aria-label="Permalink to &quot;Archive statistics&quot;">​</a></h2><p>In addition to Gmail statistics, the Dashboard displays your local archive statistics:</p><ul><li>Number of archived emails</li><li>Total archive size on the NAS</li><li>Number of archived attachments</li></ul><hr><h2 id="cache-and-refresh" tabindex="-1">Cache and refresh <a class="header-anchor" href="#cache-and-refresh" aria-label="Permalink to &quot;Cache and refresh&quot;">​</a></h2><p>Statistics are cached for 15 minutes in Redis to avoid overloading the Gmail API. The Dashboard always displays the most recent available data.</p><p>To force a refresh, reload the page.</p>',31)])])}const p=a(o,[["render",s]]);export{m as __pageData,p as default};
